.universeContainer {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: radial-gradient(ellipse at center, #0a0e1a 0%, #000000 100%);
    touch-action: none;
    cursor: grab;
    z-index: 1000;
    overflow: hidden;
}

.universeContainer.grabbing {
    cursor: grabbing;
}

.backButton {
    position: absolute;
    top: 16px;
    left: 16px;
    z-index: 1010;
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 10px 18px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    color: #e0e0e0;
    font-size: 14px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.backButton:hover {
    background: rgba(255, 255, 255, 0.12);
    border-color: rgba(255, 255, 255, 0.2);
}

.backButton svg {
    width: 18px;
    height: 18px;
    fill: #e0e0e0;
}

.coordsLabel {
    position: absolute;
    bottom: 16px;
    left: 16px;
    z-index: 1010;
    padding: 6px 12px;
    background: rgba(255, 255, 255, 0.04);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 8px;
    color: rgba(255, 255, 255, 0.35);
    font-size: 11px;
    font-family: monospace;
    pointer-events: none;
}

.previewPanel {
    position: absolute;
    bottom: 16px;
    right: 16px;
    z-index: 1010;
    width: 320px;
    max-height: 340px;
    overflow-y: auto;
    padding: 20px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 16px;
    color: #e0e0e0;
}

.previewAuthor {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 12px;
}

.previewAvatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
    border: 1px solid rgba(255, 255, 255, 0.15);
}

.previewAuthorName {
    font-size: 13px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.85);
}

.previewTitle {
    font-size: 16px;
    font-weight: 700;
    margin-bottom: 8px;
    color: #ffffff;
    line-height: 1.3;
}

.previewSnippet {
    font-size: 13px;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.55);
    margin-bottom: 16px;
    display: -webkit-box;
    -webkit-line-clamp: 4;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.previewLikes {
    font-size: 11px;
    color: rgba(255, 255, 255, 0.35);
    margin-bottom: 14px;
}

.previewReadBtn {
    display: inline-block;
    padding: 8px 22px;
    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.previewReadBtn:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

@media (max-width: 600px) {
    .previewPanel {
        width: calc(100% - 32px);
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 260px;
    }

    .backButton {
        top: 12px;
        left: 12px;
        padding: 8px 14px;
        font-size: 13px;
    }

    .coordsLabel {
        bottom: auto;
        top: 12px;
        right: 12px;
        left: auto;
    }
}

