  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts } from '../../../API/Api';
  6→import useUniverseCamera from './hooks/useUniverseCamera';
  7→import DeepSpaceLayer from './layers/DeepSpaceLayer';
  8→import MidGalaxyLayer from './layers/MidGalaxyLayer';
  9→import InteractiveLayer from './layers/InteractiveLayer';
 10→import { extractSnippet } from './utils/starUtils';
 11→import styles from './Universe.module.css';
 12→
 13→const Universe = () => {
 14→    const navigate = useNavigate();
 15→    const { user } = useAuth();
 16→    const userId = user?.userData?.[0]?.id || null;
 17→
 18→    const {
 19→        stageRef,
 20→        stageSize,
 21→        camera,
 22→        zoom,
 23→        isDragging,
 24→        centerWorld,
 25→        getLayerProps,
 26→        getViewportBounds,
 27→        stageEvents,
 28→    } = useUniverseCamera(userId);
 29→
 30→    const debounceRef = useRef(null);
 31→    const [posts, setPosts] = useState(new Map());
 32→    const [selectedPost, setSelectedPost] = useState(null);
 33→    const [pulsingId, setPulsingId] = useState(null);
 34→
 35→    // Debounced fetch on camera/zoom change
 36→    useEffect(() => {
 37→        if (debounceRef.current) clearTimeout(debounceRef.current);
 38→
 39→        debounceRef.current = setTimeout(async () => {
 40→            const bounds = getViewportBounds();
 41→            try {
 42→                const result = await getUniversePosts(bounds.minX, bounds.maxX, bounds.minY, bounds.maxY, 200);
 43→                if (result?.data) {
 44→                    setPosts(prev => {
 45→                        const next = new Map(prev);
 46→                        for (const post of result.data) {
 47→                            next.set(post.id, post);
 48→                        }
 49→                        return next;
 50→                    });
 51→                }
 52→            } catch (err) {
 53→                console.error('Failed to fetch universe posts:', err);
 54→            }
 55→        }, 400);
 56→
 57→        return () => {
 58→            if (debounceRef.current) clearTimeout(debounceRef.current);
 59→        };
 60→    }, [camera, zoom, getViewportBounds]);
 61→
 62→    const handleStarClick = useCallback((post) => {
 63→        setSelectedPost(post);
 64→        setPulsingId(post.id);
 65→        setTimeout(() => setPulsingId(null), 400);
 66→    }, []);
 67→
 68→    const handleReadPost = useCallback(() => {
 69→        if (!selectedPost) return;
 70→        navigate(`/home/post/${selectedPost.id}`);
 71→    }, [selectedPost, navigate]);
 72→
 73→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 74→    const showTitles = zoom > 0.5;
 75→
 76→    return (
 77→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
 78→            <button className={styles.backButton} onClick={() => navigate('/home')}>
 79→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
 80→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 81→                </svg>
 82→                Back
 83→            </button>
 84→
 85→            <div className={styles.coordsLabel}>
 86→                {centerWorld.x}, {centerWorld.y}
 87→            </div>
 88→
 89→            <Stage
 90→                ref={stageRef}
 91→                width={stageSize.width}
 92→                height={stageSize.height}
 93→                {...stageEvents}
 94→            >
 95→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
 96→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
 97→                <InteractiveLayer
 98→                    layerProps={getLayerProps(1.0)}
 99→                    posts={postArray}
